class Solution:
    def findIntegers(self, n: int) -> int:
        fib = [1, 2]
        for i in range(2, 31):
            fib.append(fib[-1] + fib[-2])

        ans, prev = 0, 0
        for i in range(30, -1, -1):
            if (n & (1 << i)) != 0:
                ans += fib[i]
                if prev:
                    ans -= 1
                    break
                prev = 1
            else:
                prev = 0
        return ans + 1

